import React, { useState } from 'react';
import './App.css';

function App() {
  const [objects, setObjects] = useState([]);

  const canvasWidth = 800;
  const canvasHeight = 600;
  const objectSize = 50; // размер объекта

  function addNewObject() {
    const newObj = {
      id: Date.now(),
      x: Math.random() * (canvasWidth - objectSize),
      y: Math.random() * (canvasHeight - objectSize),
      color: getRandomColor(),
      shape: 'circle',
    };
    setObjects([...objects, newObj]);
  }

  function getRandomColor() {
    const letters = '0123456789ABCDEF';
    let color = '#';
    for (let i = 0; i < 6; i++) {
      color += letters[Math.floor(Math.random() * 16)];
    }
    return color;
  }

  return (
    <div className="app-container">
      <header className="header">
        <h1>🎵 Sound Landscape</h1>
      </header>
      <div className="main">
        <aside className="sidebar">
          <button onClick={addNewObject}>Добавить объект</button>
          <button>Удалить объект</button>
          <button>Выбрать звук</button>
          <button>Play / Pause</button>
        </aside>
        <div
          className="canvas-container"
          style={{ position: 'relative', width: canvasWidth, height: canvasHeight }}
        >
          {objects.map(obj => (
            <div
              key={obj.id}
              className="obj"
              style={{
                position: 'absolute',
                left: obj.x,
                top: obj.y,
                width: objectSize,
                height: objectSize,
                backgroundColor: obj.color,
                borderRadius: obj.shape === 'circle' ? '50%' : '0%',
                cursor: 'pointer',
              }}
            ></div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default App;
